import os
import mysql.connector
from mysql.connector import errorcode

# Get file path from user input
def get_file_paths():
    return raw_input("Enter CSV file paths (comma-separated): ")

# Enable local_infile in MySQL config and Python connector
def enable_local_infile(config):
    config['mysqldb']['local_infile'] = True

# Connect to MySQL database
config = {
  'user': 'your_username',
  'password': 'your_password',
  'host': 'localhost',
  'database': 'your_database'
}
cnx = mysql.connector.connect(**config)
cursor = cnx.cursor()

# Get file paths from user input
file_paths = get_file_paths()
file_paths = [fp.strip() for fp in file_paths.split(',')]

# Enable local_infile
enable_local_infile(config)

# Execute LOAD DATA INFILE statements
for file_path in file_paths:
    try:
        cursor.execute("LOAD DATA INFILE '{}' INTO TABLE your_table FIELDS TERMINATED BY ',' ENCLOSED BY '\"' LINES TERMINATED BY '\\n';".format(file_path))
    except mysql.connector.Error as err:
        print("Failed - {}".format(err))

# Close cursor and connection
cursor.close()
cnx.close()

print("Bulk import completed successfully.")